\begin{theorem}
If $\alpha \in G_1$ such that $\alpha(\tau) = 1$, and $m$ is an integer with $m \notin \{0, 1, -1\}$, then $\alpha^{(m)} = \alpha^m$ implies that $\alpha = E$.
\end{theorem}

